head.script:
scwin.onpageload = function () {

    // 사용자정보 조회
    $c.sbm.execute(sbm_getUserInfo);   

    // 화물 - 컨테이너 구분
    const {cCase} = $c.data.getParameter();

    const codeOptions = [
        { grpCd: "TN006", compID: "acb_cargoSellClntNo_combo,acb_vehclSellClntNo_combo" } // 동부주요화주
    ];
    $c.data.setCommonCode(codeOptions);

};

/**
 * data onload
 */
scwin.ondataload = function() {

};

/**
 * UDC onload
 */
scwin.onUdcCompleted = function () {
    if (scwin._baseConditionRequested) {
        return;
    }

    scwin._baseConditionRequested = true;

    $p.setTimeout(function () {
        scwin.search_baseCondition();
    }, { "delay": 200 });
};

/**
 * udc_commonCombo가 다 세팅된 후 조회처리
 */
scwin.search_baseCondition = function() {
    // 기본 상세조회 조건 조회
    const param = {
        userId: $c.data.getMemInfo("userId")
    };
    dma_commonPopup.setEmptyValue();
    dma_commonPopup.setJSON(param);
    $c.sbm.execute(sbm_commonPopup);
};

/**
 * 사용자정보 조회 callback
 */
scwin.sbm_getUserInfo_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    // 유저 정보 필요한 경우 사용
    const {bhofficeIdx,hdofficeIdx,officeIdx,userId} = ds_userInfo.getAllJSON(0);

    /* todo NTIS 유저 정보??? 	
    IfbuserinfoMgnt userinfo = (IfbuserinfoMgnt)DComponentFactory.getComponentImpl(fbuserinfoMgntPBC.class);
    fbuserinfoDTO UserQC = new fbuserinfoDTO();
    UserQC.setUserId(UserID);
    List UserQCList = userinfo.GetUserInfo(UserQC);
    fbuserinfoDTO fbuserinfoDTOAl = (fbuserinfoDTO)UserQCList.get(0);
    double HdofficeIdx= fbuserinfoDTOAl.getHdofficeCd();
    double BhofficeIdx = fbuserinfoDTOAl.getBhofficeCd();
    double OfficeIdx= fbuserinfoDTOAl.getOfcCd();
    */

};

/**
 * 기본 상세조회 조건 조회 callback
 */
scwin.sbm_commonPopup_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code == 0) {

        ds_cond.setJSON(e.responseJSON.GAUCE);

        if (ds_cond.getTotalRow() < 1) {
            $c.win.alert("조회조건이 존재하지 않습니다.").then(() => {
                const iRow = ds_cond.insertRow();
                ds_cond.setCellData(iRow, "userId", $c.data.getMemInfo("userId"));
            });
        } else {
            // binding 처리
            ds_cond.setRowPosition(0);
        }
    }
};

/**
 * [닫기] - popup close
 */
scwin.btn_close_onclick = function (e) {
    // window.close();
    $c.win.closePopup();
};

/**
 * [조회조건저장]
 */
scwin.btn_save_onclick = function (e) {
    scwin.setValue();
};

/**
 * 조회조건저장
 */
scwin.setValue = function (e) {

    if (ed_cargoDate1.getValue() > ed_cargoDate2.getValue() || ed_vehclDate1.getValue() > ed_vehclDate2.getValue()) {
        $c.win.alert("조회 기간이 잘못설정 되었습니다.");
        return;
    }

    const {cargoCidx, vehclCidx} = ds_cond.getRowJSON(0);

    if (cargoCidx == 0 || vehclCidx == 0) {
        $c.win.alert("영업소가 선택되지 않았습니다.");
        return;
    }

    // 20171122 조회기간 한달이내만 검색가능하게 변경
    const startDate = new Date($c.date.formatDate(ed_cargoDate1.getValue(), "date"));
    const endDate = new Date($c.date.formatDate(ed_cargoDate2.getValue(), "date"));
    if (scwin.isOverOneMonth(startDate, endDate)) {
        $c.win.alert("조회기간을 한달 이내로 설정 해 주세요.").then(() => {
            ed_cargoDate2.focus();
        });
        return;
    }

    let {hdoIdx: cargoHdidx, bhoIdx: cargoBhidx, offIdx: cargoOfcidx} = dma_comComboCargo.getJSON();
    let {hdoIdx: vehclHdidx, bhoIdx: vehclBhidx, offIdx: vehclOfcidx} = dma_comComboVehcl.getJSON();

    ds_cond.setCellData(0, "cargoHdidx", cargoHdidx);
    ds_cond.setCellData(0, "cargoBhidx", cargoBhidx);
    ds_cond.setCellData(0, "cargoOfcidx", cargoOfcidx);
    ds_cond.setCellData(0, "vehclHdidx", vehclHdidx);
    ds_cond.setCellData(0, "vehclBhidx", vehclBhidx);
    ds_cond.setCellData(0, "vehclOfcidx", vehclOfcidx);

    $c.sbm.execute(sbm_cond);
};

/**
 * 조회조건저장 callback
 */
scwin.sbm_cond_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code == 0) {

        const pFrame = opener.$p.getComponentById($c.data.getParameter().pFrame);
        $c.win.alert("조회조건 저장에 성공하였습니다.").then(() => {

            pFrame.scope.scwin.loadcomplete();
            window.close();

        });

    }
};

/**
 * 화물정보 검색 구분값 onchange
 */
scwin.acb_cargoSrchTyp_onchange = function (info) {

};

/**
 * 화물정보 조회기간
 */
scwin.acb_cargoDateTyp_onchange = function (info) {
    scwin.f_dateSetting(info.newValue, 'cargo');
};

/**
 * 차량정보 조회기간
 */
scwin.acb_vehclDateTyp_onchange = function (info) {
    scwin.f_dateSetting(info.newValue, 'car');
};

/**
 * 당일 / 금주 / 금월 / 전월 / 지정 - 조회기간 세팅1
 */
scwin.f_dateSetting = function (selObj, cas) {
    if (selObj == 1) {//금일
        scwin.f_eventRadioClick(cas, '1');
    } else if (selObj == 2) {//금주
        scwin.f_eventRadioClick(cas, '2');
    } else if (selObj == 3) {//금월
        scwin.f_eventRadioClick(cas, '3');
    } else if (selObj == 4) {//전월
        scwin.f_eventRadioClick(cas, '4');
    } else if (selObj == 5) {//지정
    }
};

/**
 * 당일 / 금주 / 금월 / 전월 / 지정 - 조회기간 세팅2
 */
scwin.f_eventRadioClick = function (obj, type) {
    scwin.vToDate = $c.date.getServerDateTime("yyyyMMdd"); // 서버를 기준으로 현재 날짜 반환 

    const toDate = $c.date.getServerDateTime("yyyyMMdd");

    switch (type) {

        // 당일
        case '1': {
            // Object 에 날짜 입력(날짜는 20080101 형식)
            if (obj == 'car') {
                ed_vehclDate1.setValue(toDate);
                ed_vehclDate2.setValue(toDate);
            } else {
                ed_cargoDate1.setValue(toDate);
                ed_cargoDate2.setValue(toDate);
            }

            break;
        }

        // 금주
        case '2': {

            const range = scwin.getWeekRangeSunToSat(new Date());
            sDt1 = range.sDt1;
            sDt2 = range.sDt2;

            if (obj == 'car') {
                ed_vehclDate1.setValue(sDt1);
                ed_vehclDate2.setValue(sDt2);
            } else {
                ed_cargoDate1.setValue(sDt1);
                ed_cargoDate2.setValue(sDt2);
            }

            break;
        }

        // 금월
        case '3': {

            const yyyyMM = toDate.slice(0, 6);

            // 조회 시작일
            sDt1 = `${yyyyMM}01`;

            // 조회 종료일				
            sDt2 = `${yyyyMM}${$c.date.getLastDateOfMonth(yyyyMM)}`;

            if (obj == 'car') {
                ed_vehclDate1.setValue(sDt1);
                ed_vehclDate2.setValue(sDt2);
            } else {
                ed_cargoDate1.setValue(sDt1);
                ed_cargoDate2.setValue(sDt2);
            }

            break;
        }

        // 전월
        case '4': {

            // 조회 시작일
            sDt1 = $c.date.getDateAddMonthDirection(toDate, "-1", "F");

            // 조회 종료일				
            sDt2 = $c.date.getDateAddMonthDirection(toDate, "-1", "L");

            if (obj == 'car') {
                ed_vehclDate1.setValue(sDt1);
                ed_vehclDate2.setValue(sDt2);
            } else {
                ed_cargoDate1.setValue(sDt1);
                ed_cargoDate2.setValue(sDt2);
            }

            break;
        }

        // 지정
        case '5': {
            break;
        }
    }
};

/**
 * 금주 세팅
 */
scwin.getWeekRangeSunToSat = function(date) {
    function pad2(n) {
        return (n < 10 ? "0" : "") + n;
    }
    function yyyymmdd(d) {
        return d.getFullYear() + pad2(d.getMonth() + 1) + pad2(d.getDate());
    }
    var d = date ? new Date(date.getTime()) : new Date();
    var day = d.getDay(); // 0(일)~6(토)

    var sun = new Date(d);
    sun.setDate(d.getDate() - day);

    var sat = new Date(d);
    sat.setDate(d.getDate() + (6 - day));

    return { sDt1: yyyymmdd(sun), sDt2: yyyymmdd(sat) };
};

/**
 * 일수 기준 체크 - 31일 초과 여부
 */
scwin.isOverOneMonth = function(startDate, endDate) {
    const s = new Date(startDate);
    const e = new Date(endDate);

    const diffDays = (e - s) / (1000 * 60 * 60 * 24);

    return diffDays > 31;
};

scwin.acb_cargoSrchTyp_onviewchange = function (info) {
    ed_cargoSrchCnd.setValue("");
};
